// ===================================================================
// SLIDER (custom, themed)
// ===================================================================
function Slider({ label, value, min, max, step, unit, onChange, format }) {
  const pct = ((value - min) / (max - min)) * 100;
  return (
    <div className="mb-5">
      <div className="flex items-baseline justify-between mb-2">
        <label className="hf-body text-[11px] uppercase tracking-[0.14em]" style={{ color: C.textMuted }}>
          {label}
        </label>
        <span className="hf-mono text-sm tabular-nums" style={{ color: C.gold }}>
          {format ? format(value) : value.toFixed(step < 1 ? 2 : 0)}
          {unit && <span style={{ color: C.textDim }}> {unit}</span>}
        </span>
      </div>
      <div className="relative">
        <input
          type="range"
          min={min}
          max={max}
          step={step}
          value={value}
          onChange={(e) => onChange(parseFloat(e.target.value))}
          className="hf-slider w-full"
          style={{
            background: `linear-gradient(to right, ${C.gold} 0%, ${C.gold} ${pct}%, ${C.border} ${pct}%, ${C.border} 100%)`,
          }}
        />
      </div>
    </div>
  );
}

