function AssetConfigurator({ asset, onChange }) {
  const set = (k, v) => onChange({ ...asset, [k]: v });
  const eta_rt = asset.eta_c * asset.eta_d;

  const applyPreset = (preset) => {
    onChange({ ...asset, pMax: preset.power, eCap: preset.capacity });
  };

  return (
    <aside className="hf-panel p-6 self-start" style={{ minWidth: 320 }}>
      <div className="flex items-baseline justify-between mb-4">
        <h2 className="hf-display text-xl" style={{ color: C.text }}>
          Asset
        </h2>
        <span className="hf-mono text-[10px] uppercase tracking-[0.15em]" style={{ color: C.textDim }}>
          Generic spec
        </span>
      </div>

      <div className="grid grid-cols-2 gap-1.5 mb-6">
        {PRESETS.map((p) => {
          const active = Math.abs(asset.pMax - p.power) < 0.01 && Math.abs(asset.eCap - p.capacity) < 0.01;
          return (
            <button
              key={p.id}
              onClick={() => applyPreset(p)}
              className="hf-preset-btn hf-mono text-[10px] uppercase tracking-wider py-2 px-2 rounded transition-all"
              style={{
                color: active ? C.bg : C.textMuted,
                background: active ? C.gold : C.bgRaised,
                border: `1px solid ${active ? C.gold : C.border}`,
              }}
            >
              {p.label}
            </button>
          );
        })}
      </div>

      <div className="hf-divider mb-5" />

      <Slider
        label="Power rating"
        value={asset.pMax}
        min={0.5}
        max={50}
        step={0.5}
        unit="MW"
        onChange={(v) => set("pMax", v)}
        format={(v) => v.toFixed(v >= 10 ? 0 : 1)}
      />
      <Slider
        label="Energy capacity"
        value={asset.eCap}
        min={0.5}
        max={200}
        step={0.5}
        unit="MWh"
        onChange={(v) => set("eCap", v)}
        format={(v) => v.toFixed(v >= 10 ? 0 : 1)}
      />

      <div className="my-4 px-3 py-2 rounded hf-mono text-[11px]" style={{ background: C.bgRaised, color: C.textMuted }}>
        Duration: <span style={{ color: C.gold }}>{(asset.eCap / asset.pMax).toFixed(2)}h</span>
      </div>

      <Slider
        label="Round-trip efficiency"
        value={eta_rt}
        min={0.70}
        max={0.98}
        step={0.01}
        unit="%"
        onChange={(v) => {
          const e = Math.sqrt(v);
          onChange({ ...asset, eta_c: e, eta_d: e });
        }}
        format={(v) => (v * 100).toFixed(0)}
      />

      <Slider
        label="SoC min"
        value={asset.socMin}
        min={0}
        max={0.4}
        step={0.05}
        unit="%"
        onChange={(v) => set("socMin", v)}
        format={(v) => (v * 100).toFixed(0)}
      />
      <Slider
        label="SoC max"
        value={asset.socMax}
        min={0.6}
        max={1.0}
        step={0.05}
        unit="%"
        onChange={(v) => set("socMax", v)}
        format={(v) => (v * 100).toFixed(0)}
      />
      <Slider
        label="Daily cycle limit"
        value={asset.cycleLimit}
        min={0.5}
        max={3.0}
        step={0.1}
        unit="cyc"
        onChange={(v) => set("cycleLimit", v)}
        format={(v) => v.toFixed(1)}
      />
      <Slider
        label="Cycle cost"
        value={asset.cycleCost}
        min={0}
        max={20}
        step={0.5}
        unit="€/MWh"
        onChange={(v) => set("cycleCost", v)}
        format={(v) => v.toFixed(1)}
      />
    </aside>
  );
}

