// ===================================================================
// HERO CHART — custom SVG with three stacked panels:
//   1. Price curve (top), with negative regions filled violet
//   2. Dispatch bars (middle): charge above 0 in blue, discharge below in coral
//   3. SoC trajectory (bottom): gold line with bounds rails
// ===================================================================
function HeroChart({ prices, result, asset, dayLabel, width = 900, height = 480 }) {
  const M = { l: 60, r: 30, t: 30, b: 36 };
  const W = width - M.l - M.r;
  const H = height - M.t - M.b;

  // Stack heights: price 45%, dispatch 30%, soc 25%
  const hPrice = H * 0.45;
  const hDisp = H * 0.30;
  const hSoc = H * 0.25;
  const yPriceTop = M.t;
  const yDispTop = M.t + hPrice + 8;
  const ySocTop = M.t + hPrice + 8 + hDisp + 8;

  const n = prices.length;
  const xStep = W / n;
  const x = (i) => M.l + i * xStep;

  // Price scaling
  const pMin = Math.min(...prices, 0);
  const pMax = Math.max(...prices);
  const pSpan = pMax - pMin || 1;
  const yPrice = (v) => yPriceTop + hPrice * (1 - (v - pMin) / pSpan);
  const yPriceZero = yPrice(0);

  // Dispatch scaling — symmetric around 0
  const maxAbsDisp = Math.max(asset.pMax, 0.5);
  const yDispMid = yDispTop + hDisp / 2;
  const yDisp = (mw) => yDispMid - (mw / maxAbsDisp) * (hDisp / 2);

  // SoC scaling
  const ySoc = (e) => ySocTop + hSoc * (1 - (e - 0) / asset.eCap);
  const yEmin = ySoc(asset.eCap * asset.socMin);
  const yEmax = ySoc(asset.eCap * asset.socMax);

  // Build price polyline
  const pricePathD = prices.map((p, i) => `${i === 0 ? "M" : "L"} ${x(i) + xStep / 2} ${yPrice(p)}`).join(" ");

  // Negative-price area path (only segments below 0)
  const negSegments = [];
  let segStart = -1;
  for (let i = 0; i < n; i++) {
    if (prices[i] < 0 && segStart < 0) segStart = i;
    if ((prices[i] >= 0 || i === n - 1) && segStart >= 0) {
      const end = prices[i] < 0 ? i : i - 1;
      negSegments.push({ start: segStart, end });
      segStart = -1;
    }
  }

  // X-axis hour labels
  const hourTicks = [0, 3, 6, 9, 12, 15, 18, 21, 24];

  // Format hour label
  const hourLabel = (h) => `${h.toString().padStart(2, "0")}:00`;

  return (
    <div className="hf-panel p-5">
      <div className="flex items-baseline justify-between mb-1">
        <h2 className="hf-display text-xl" style={{ color: C.text }}>
          Optimal dispatch &nbsp;<span style={{ color: C.textDim, fontStyle: "italic", fontSize: "0.85em" }}>· {dayLabel}</span>
        </h2>
        <div className="flex items-center gap-4 hf-mono text-[10px] uppercase tracking-wider" style={{ color: C.textMuted }}>
          <span><span style={{ color: C.gold }}>━</span> Price</span>
          <span><span style={{ color: C.charge }}>▲</span> Charge</span>
          <span><span style={{ color: C.discharge }}>▼</span> Discharge</span>
          <span><span style={{ color: C.gold }}>┄</span> SoC</span>
        </div>
      </div>
      <svg viewBox={`0 0 ${width} ${height}`} className="w-full" style={{ display: "block" }}>
        <defs>
          <linearGradient id="priceFill" x1="0" x2="0" y1="0" y2="1">
            <stop offset="0%" stopColor={C.gold} stopOpacity="0.15" />
            <stop offset="100%" stopColor={C.gold} stopOpacity="0" />
          </linearGradient>
          <linearGradient id="negFill" x1="0" x2="0" y1="0" y2="1">
            <stop offset="0%" stopColor={C.negative} stopOpacity="0" />
            <stop offset="100%" stopColor={C.negative} stopOpacity="0.5" />
          </linearGradient>
        </defs>

        {/* === Hour grid === */}
        {hourTicks.map((h) => (
          <line
            key={h}
            x1={x(h * 4)}
            x2={x(h * 4)}
            y1={M.t}
            y2={height - M.b}
            stroke={C.border}
            strokeWidth="1"
            strokeDasharray="2 4"
            opacity="0.4"
          />
        ))}

        {/* === PRICE PANEL === */}
        {/* Frame */}
        <rect x={M.l} y={yPriceTop} width={W} height={hPrice} fill={C.bgRaised} stroke={C.border} />

        {/* Price area fill above zero */}
        <path
          d={`${pricePathD} L ${x(n - 1) + xStep / 2} ${yPriceZero} L ${x(0) + xStep / 2} ${yPriceZero} Z`}
          fill="url(#priceFill)"
        />

        {/* Negative-price highlight blocks */}
        {negSegments.map((seg, idx) => {
          const xs = x(seg.start);
          const xe = x(seg.end + 1);
          return (
            <g key={idx}>
              <rect
                x={xs}
                y={yPriceZero}
                width={xe - xs}
                height={yPriceTop + hPrice - yPriceZero}
                fill={C.negative}
                opacity="0.18"
              />
              <line x1={xs} x2={xe} y1={yPriceZero} y2={yPriceZero} stroke={C.negative} strokeWidth="1" />
              {seg.end - seg.start < 3 && (
                <text
                  x={(xs + xe) / 2}
                  y={yPriceTop + hPrice - 6}
                  textAnchor="middle"
                  fontSize="9"
                  fill={C.negative}
                  fontFamily="JetBrains Mono, monospace"
                >
                  €{prices[seg.start].toFixed(0)}
                </text>
              )}
            </g>
          );
        })}

        {/* Zero baseline if negative prices */}
        {pMin < 0 && (
          <line x1={M.l} x2={M.l + W} y1={yPriceZero} y2={yPriceZero} stroke={C.textDim} strokeWidth="1" strokeDasharray="3 3" />
        )}

        {/* Price line */}
        <path d={pricePathD} stroke={C.gold} strokeWidth="1.5" fill="none" />

        {/* Price y-axis labels */}
        {[pMin, pMax].map((v, idx) => (
          <text
            key={idx}
            x={M.l - 8}
            y={yPrice(v) + 4}
            textAnchor="end"
            fontSize="10"
            fill={C.textMuted}
            fontFamily="JetBrains Mono, monospace"
          >
            €{v.toFixed(0)}
          </text>
        ))}

        <text
          x={M.l + 6}
          y={yPriceTop + 14}
          fontSize="9"
          fontFamily="Manrope, sans-serif"
          fill={C.textMuted}
          letterSpacing="0.12em"
          textTransform="uppercase"
        >
          PRICE €/MWh
        </text>

        {/* === DISPATCH PANEL === */}
        <rect x={M.l} y={yDispTop} width={W} height={hDisp} fill={C.bgRaised} stroke={C.border} />
        <line x1={M.l} x2={M.l + W} y1={yDispMid} y2={yDispMid} stroke={C.textDim} strokeWidth="1" />

        {/* Bars */}
        {prices.map((_, i) => {
          const c = result.charge[i];
          const d = result.discharge[i];
          const bw = xStep * 0.85;
          const bx = x(i) + (xStep - bw) / 2;
          const out = [];
          if (c > 0.001) {
            const yTop = yDisp(c);
            out.push(
              <rect key={`c${i}`} x={bx} y={yTop} width={bw} height={Math.max(1, yDispMid - yTop)} fill={C.charge} opacity="0.85" />
            );
          }
          if (d > 0.001) {
            const yBot = yDisp(-d);
            out.push(
              <rect key={`d${i}`} x={bx} y={yDispMid} width={bw} height={Math.max(1, yBot - yDispMid)} fill={C.discharge} opacity="0.85" />
            );
          }
          return out;
        })}

        <text
          x={M.l + 6}
          y={yDispTop + 12}
          fontSize="9"
          fontFamily="Manrope, sans-serif"
          fill={C.textMuted}
          letterSpacing="0.12em"
        >
          DISPATCH MW
        </text>
        <text
          x={M.l - 8}
          y={yDispTop + 12}
          textAnchor="end"
          fontSize="10"
          fill={C.charge}
          fontFamily="JetBrains Mono, monospace"
        >
          +{maxAbsDisp.toFixed(maxAbsDisp >= 10 ? 0 : 1)}
        </text>
        <text
          x={M.l - 8}
          y={yDispTop + hDisp - 2}
          textAnchor="end"
          fontSize="10"
          fill={C.discharge}
          fontFamily="JetBrains Mono, monospace"
        >
          −{maxAbsDisp.toFixed(maxAbsDisp >= 10 ? 0 : 1)}
        </text>

        {/* === SOC PANEL === */}
        <rect x={M.l} y={ySocTop} width={W} height={hSoc} fill={C.bgRaised} stroke={C.border} />
        {/* SoC bound rails */}
        <line x1={M.l} x2={M.l + W} y1={yEmin} y2={yEmin} stroke={C.discharge} strokeWidth="1" strokeDasharray="3 3" opacity="0.4" />
        <line x1={M.l} x2={M.l + W} y1={yEmax} y2={yEmax} stroke={C.charge} strokeWidth="1" strokeDasharray="3 3" opacity="0.4" />
        {/* SoC line — sample boundary points */}
        <path
          d={Array.from({ length: n + 1 }, (_, i) => `${i === 0 ? "M" : "L"} ${x(i)} ${ySoc(result.soc[i])}`).join(" ")}
          stroke={C.gold}
          strokeWidth="1.8"
          fill="none"
        />
        <text x={M.l + 6} y={ySocTop + 12} fontSize="9" fontFamily="Manrope, sans-serif" fill={C.textMuted} letterSpacing="0.12em">
          STATE OF CHARGE MWh
        </text>
        <text
          x={M.l - 8}
          y={yEmin + 4}
          textAnchor="end"
          fontSize="9"
          fill={C.discharge}
          fontFamily="JetBrains Mono, monospace"
        >
          {(asset.eCap * asset.socMin).toFixed(2)}
        </text>
        <text
          x={M.l - 8}
          y={yEmax + 4}
          textAnchor="end"
          fontSize="9"
          fill={C.charge}
          fontFamily="JetBrains Mono, monospace"
        >
          {(asset.eCap * asset.socMax).toFixed(2)}
        </text>

        {/* === HOUR AXIS === */}
        {hourTicks.map((h) => (
          <text
            key={h}
            x={x(h * 4)}
            y={height - M.b + 18}
            textAnchor="middle"
            fontSize="10"
            fill={C.textDim}
            fontFamily="JetBrains Mono, monospace"
          >
            {hourLabel(h)}
          </text>
        ))}
      </svg>
    </div>
  );
}

// ===================================================================
// DAY STRIP — 29 mini-tiles with sparkline of price shape
// ===================================================================
function DayStrip({ days, selectedIdx, onSelect, monthlyResults }) {
  return (
    <div className="hf-panel p-4">
      <div className="flex items-baseline justify-between mb-3">
        <h3 className="hf-display text-base" style={{ color: C.text }}>
          Day selector <span style={{ color: C.textDim, fontStyle: "italic", fontSize: "0.85em" }}>· April 2025</span>
        </h3>
        <span className="hf-mono text-[10px] uppercase tracking-wider" style={{ color: C.textMuted }}>
          29 days · click to inspect
        </span>
      </div>
      <div className="flex gap-1.5 overflow-x-auto pb-1" style={{ scrollbarWidth: "thin" }}>
        {days.map((day, i) => {
          const sel = i === selectedIdx;
          const r = monthlyResults?.[i];
          const pMax = Math.max(...day.p);
          const pMin = Math.min(...day.p);
          const tw = 56;
          const th = 36;
          const sparkPath = day.p
            .map((p, idx) => {
              const xx = (idx / (day.p.length - 1)) * tw;
              const yy = th - ((p - pMin) / (pMax - pMin || 1)) * th;
              return `${idx === 0 ? "M" : "L"} ${xx.toFixed(1)} ${yy.toFixed(1)}`;
            })
            .join(" ");
          return (
            <button
              key={day.d}
              onClick={() => onSelect(i)}
              className="flex-shrink-0 rounded transition-all"
              style={{
                width: 64,
                background: sel ? C.surfaceHi : C.bgRaised,
                border: `1.5px solid ${sel ? C.gold : C.border}`,
                padding: "4px",
                cursor: "pointer",
              }}
            >
              <div className="hf-mono text-[10px] mb-0.5" style={{ color: sel ? C.gold : C.textMuted }}>
                {day.d}
              </div>
              <svg width={tw} height={th} style={{ display: "block" }}>
                <path d={sparkPath} stroke={sel ? C.gold : C.textMuted} strokeWidth="1" fill="none" />
              </svg>
              {r && (
                <div className="hf-mono text-[9px] mt-0.5 tabular-nums" style={{ color: sel ? C.gold : C.textDim }}>
                  €{fmtMoneyCompact(r.netRevenue)}
                </div>
              )}
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ===================================================================
// FORECASTER PANEL — bar chart of three forecaster strategies
// ===================================================================
function ForecasterPanel({ asset }) {
  const oracle = FORECASTER_BENCHMARK.perfect.revPerMwhPerYear;
  const bars = [
    { ...FORECASTER_BENCHMARK.perfect, color: C.gold },
    { ...FORECASTER_BENCHMARK.smart,   color: C.charge },
    { ...FORECASTER_BENCHMARK.naive,   color: C.discharge },
  ];

  return (
    <div className="hf-panel p-5">
      <div className="flex items-baseline justify-between mb-4">
        <h3 className="hf-display text-lg" style={{ color: C.text }}>
          Forecaster comparison
        </h3>
        <span className="hf-mono text-[10px] uppercase tracking-wider" style={{ color: C.textMuted }}>
          30-day backtest · 1MW/2MWh
        </span>
      </div>
      <p className="hf-body text-xs mb-5" style={{ color: C.textMuted, lineHeight: 1.6 }}>
        Without perfect knowledge of tomorrow's prices, the operator depends on a forecast.
        HelleniFlex ships with three: a Ridge regression on lagged DAM features (Smart),
        a same-hour-last-week baseline (Naive), and a Perfect Foresight oracle that
        defines the upper bound. The gap is what better forecasting buys you.
      </p>
      <div className="space-y-3">
        {bars.map((b) => {
          const pct = (b.revPerMwhPerYear / oracle) * 100;
          return (
            <div key={b.label}>
              <div className="flex items-baseline justify-between mb-1">
                <span className="hf-body text-sm" style={{ color: C.text }}>{b.label}</span>
                <span className="hf-mono text-sm tabular-nums" style={{ color: b.color }}>
                  €{fmtMoney(b.revPerMwhPerYear)}<span style={{ color: C.textDim, fontSize: "0.8em" }}> /MWh/yr</span>
                </span>
              </div>
              <div className="relative h-2 rounded" style={{ background: C.bgRaised }}>
                <div
                  className="absolute top-0 left-0 h-full rounded transition-all duration-500"
                  style={{ background: b.color, width: `${pct}%`, opacity: 0.85 }}
                />
              </div>
              <div className="flex items-baseline justify-between mt-1">
                <span className="hf-body text-[10px]" style={{ color: C.textDim }}>{b.note}</span>
                <span className="hf-mono text-[10px] tabular-nums" style={{ color: C.textMuted }}>
                  {pct.toFixed(1)}% of oracle
                </span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ===================================================================
// MONTHLY SUMMARY
// ===================================================================
function MonthlySummary({ monthlyResults, asset, isComputing, progress }) {
  const total = monthlyResults?.reduce((s, r) => s + r.netRevenue, 0) ?? 0;
  const avgDay = monthlyResults ? total / monthlyResults.length : 0;
  const annualized = avgDay * 365 / asset.eCap;
  const totalCycles = monthlyResults?.reduce((s, r) => s + r.cycles, 0) ?? 0;
  const totalThroughput = monthlyResults?.reduce((s, r) => s + r.throughput, 0) ?? 0;

  return (
    <div className="hf-panel p-5">
      <div className="flex items-baseline justify-between mb-4">
        <h3 className="hf-display text-lg" style={{ color: C.text }}>
          29-day live backtest
        </h3>
        <span className="hf-mono text-[10px] uppercase tracking-wider" style={{ color: C.textMuted }}>
          {isComputing ? `optimizing… ${progress}/29` : "current asset config"}
        </span>
      </div>
      {isComputing && (
        <div className="h-1 mb-4 rounded overflow-hidden" style={{ background: C.bgRaised }}>
          <div
            className="h-full rounded transition-all"
            style={{ background: C.gold, width: `${(progress / 29) * 100}%` }}
          />
        </div>
      )}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <div className="hf-body text-[10px] uppercase tracking-[0.18em] mb-1" style={{ color: C.textMuted }}>
            Total revenue
          </div>
          <div className="hf-mono text-2xl tabular-nums" style={{ color: C.gold }}>
            €{fmtMoney(total)}
          </div>
        </div>
        <div>
          <div className="hf-body text-[10px] uppercase tracking-[0.18em] mb-1" style={{ color: C.textMuted }}>
            Annualized
          </div>
          <div className="hf-mono text-2xl tabular-nums" style={{ color: C.text }}>
            €{fmtMoney(annualized)}<span className="text-xs" style={{ color: C.textDim }}>/MWh/yr</span>
          </div>
        </div>
        <div>
          <div className="hf-body text-[10px] uppercase tracking-[0.18em] mb-1" style={{ color: C.textMuted }}>
            Equiv. cycles
          </div>
          <div className="hf-mono text-2xl tabular-nums" style={{ color: C.text }}>
            {totalCycles.toFixed(1)}
          </div>
        </div>
        <div>
          <div className="hf-body text-[10px] uppercase tracking-[0.18em] mb-1" style={{ color: C.textMuted }}>
            Throughput
          </div>
          <div className="hf-mono text-2xl tabular-nums" style={{ color: C.text }}>
            {fmtMoney(totalThroughput, 1)}<span className="text-xs" style={{ color: C.textDim }}> MWh</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// ===================================================================
// CUSTOM CSS — fonts, panel styling, slider, Greek-key motif
// ===================================================================
const CUSTOM_CSS = `
@import url('https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,400;0,9..144,500;0,9..144,600;1,9..144,400;1,9..144,500;1,9..144,600&family=JetBrains+Mono:wght@400;500&family=Manrope:wght@300;400;500;600&display=swap');

.hf-display { font-family: 'Fraunces', 'Iowan Old Style', 'Palatino', serif; font-feature-settings: 'liga' 1, 'kern' 1; font-variation-settings: 'opsz' 144; }
.hf-body    { font-family: 'Manrope', system-ui, sans-serif; }
.hf-mono    { font-family: 'JetBrains Mono', 'SF Mono', 'Menlo', monospace; font-variant-numeric: tabular-nums; }

.hf-panel {
  background: ${C.surface};
  border: 1px solid ${C.border};
  border-radius: 4px;
}

.hf-divider {
  height: 1px;
  background: linear-gradient(to right, transparent, ${C.goldDim}, transparent);
}

/* Greek-key (meander) motif — thin SVG strip */
.hf-meander {
  width: 100%;
  max-width: 280px;
  height: 14px;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='40' height='14' viewBox='0 0 40 14'><path d='M0 13 L0 3 L8 3 L8 9 L4 9 L4 6 L12 6 L12 13 M12 13 L20 13 L20 3 L28 3 L28 9 L24 9 L24 6 L32 6 L32 13' fill='none' stroke='${encodeURIComponent(C.meander)}' stroke-width='1.4'/></svg>");
  background-repeat: repeat-x;
  background-size: auto 14px;
  opacity: 0.7;
}

/* Custom range slider styling */
.hf-slider {
  -webkit-appearance: none;
  appearance: none;
  height: 4px;
  border-radius: 2px;
  outline: none;
  cursor: pointer;
  transition: opacity 0.2s;
}
.hf-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: ${C.gold};
  border: 2px solid ${C.bg};
  cursor: pointer;
  box-shadow: 0 0 0 1px ${C.gold};
  transition: transform 0.1s;
}
.hf-slider::-webkit-slider-thumb:hover { transform: scale(1.2); }
.hf-slider::-moz-range-thumb {
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: ${C.gold};
  border: 2px solid ${C.bg};
  cursor: pointer;
  box-shadow: 0 0 0 1px ${C.gold};
}

/* Preset button hover */
.hf-preset-btn { cursor: pointer; }
.hf-preset-btn:hover { filter: brightness(1.2); }

/* Subtle film-grain over the whole app */
.hf-grain::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence baseFrequency='0.85' numOctaves='2' /><feColorMatrix values='0 0 0 0 0.92  0 0 0 0 0.88  0 0 0 0 0.78  0 0 0 0.05 0'/></filter><rect width='100%25' height='100%25' filter='url(%23n)'/></svg>");
  opacity: 0.7;
  mix-blend-mode: overlay;
  z-index: 9999;
}

/* Scrollbar */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: ${C.bg}; }
::-webkit-scrollbar-thumb { background: ${C.border}; border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: ${C.borderBright}; }
`;

// ===================================================================
// APP ROOT
// ===================================================================
function App() {
  const [asset, setAsset] = useState(DEFAULT_ASSET);
  const [selectedDayIdx, setSelectedDayIdx] = useState(14); // default to 04-15 (has negative price)
  const [monthlyResults, setMonthlyResults] = useState(null);
  const [isComputing, setIsComputing] = useState(true);
  const [progress, setProgress] = useState(0);
  const computeKey = useRef(0);

  // Live single-day result (instant)
  const selectedResult = useMemo(() => {
    return optimize(PRICES[selectedDayIdx].p, asset);
  }, [asset, selectedDayIdx]);

  // Async chunked monthly recompute, debounced
  useEffect(() => {
    const myKey = ++computeKey.current;
    setIsComputing(true);
    setProgress(0);

    const debounceMs = 200;
    const debounce = setTimeout(() => {
      (async () => {
        const results = [];
        for (let i = 0; i < PRICES.length; i++) {
          if (computeKey.current !== myKey) return; // canceled by newer change
          const r = optimize(PRICES[i].p, asset);
          results.push(r);
          if (i % 3 === 2) {
            setProgress(i + 1);
            await new Promise((res) => setTimeout(res, 0));
          }
        }
        if (computeKey.current === myKey) {
          setMonthlyResults(results);
          setProgress(PRICES.length);
          setIsComputing(false);
        }
      })();
    }, debounceMs);

    return () => clearTimeout(debounce);
  }, [asset]);

  const selectedDay = PRICES[selectedDayIdx];
  const dayLabel = formatDate(selectedDay.d);

  return (
    <div className="hf-grain min-h-screen w-full" style={{ background: C.bg, color: C.text }}>
      <style dangerouslySetInnerHTML={{ __html: CUSTOM_CSS }} />

      <div className="max-w-[1400px] mx-auto">
        <Header />

        <div className="grid grid-cols-12 gap-5 p-8">
          {/* SIDEBAR */}
          <div className="col-span-12 lg:col-span-3">
            <AssetConfigurator asset={asset} onChange={setAsset} />
          </div>

          {/* MAIN AREA */}
          <div className="col-span-12 lg:col-span-9 space-y-5">
            {/* KPI strip */}
            <div className="flex gap-5 flex-wrap">
              <Kpi
                label="Daily revenue"
                value={`€${fmtMoney(selectedResult.netRevenue, 2)}`}
                sub={`Cycle cost: €${fmtMoney(selectedResult.throughput * asset.cycleCost, 2)}`}
                accent={C.gold}
              />
              <Kpi
                label="Cycles used"
                value={selectedResult.cycles.toFixed(2)}
                unit={`/ ${asset.cycleLimit.toFixed(1)}`}
                sub={`${((selectedResult.cycles / asset.cycleLimit) * 100).toFixed(0)}% of daily limit`}
                accent={C.text}
              />
              <Kpi
                label="Throughput"
                value={fmtMoney(selectedResult.throughput, 2)}
                unit="MWh"
                sub={`Charge ${selectedResult.chargeMwh.toFixed(2)} · Discharge ${selectedResult.dischargeMwh.toFixed(2)}`}
                accent={C.text}
              />
              <Kpi
                label="Annualized"
                value={`€${fmtMoney((selectedResult.netRevenue * 365) / asset.eCap)}`}
                unit="/MWh/yr"
                sub="single-day extrapolation"
                accent={C.gold}
              />
            </div>

            {/* Hero chart */}
            <HeroChart
              prices={selectedDay.p}
              result={selectedResult}
              asset={asset}
              dayLabel={dayLabel}
              width={900}
              height={460}
            />

            {/* Day strip */}
            <DayStrip
              days={PRICES}
              selectedIdx={selectedDayIdx}
              onSelect={setSelectedDayIdx}
              monthlyResults={monthlyResults}
            />

            {/* Bottom row: monthly + forecaster */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <MonthlySummary
                monthlyResults={monthlyResults}
                asset={asset}
                isComputing={isComputing}
                progress={progress}
              />
              <ForecasterPanel asset={asset} />
            </div>

            {/* Footer / framework note */}
            <div className="hf-panel p-5">
              <div className="flex items-baseline justify-between mb-2">
                <h4 className="hf-display text-base" style={{ color: C.text }}>
                  How this works
                </h4>
                <span className="hf-mono text-[10px] uppercase tracking-wider" style={{ color: C.textMuted }}>
                  hackathon submission
                </span>
              </div>
              <p className="hf-body text-xs leading-relaxed" style={{ color: C.textMuted }}>
                The dashboard runs an in-browser LP-style heuristic that reproduces the
                full Python <span className="hf-mono" style={{ color: C.gold }}>helleniflex</span> MILP within{" "}
                <span style={{ color: C.text }}>0.5%</span> on the 29-day sample shown.
                The Python package consumes real HEnEx EL-DAM Excel files directly &mdash;{" "}
                <span style={{ color: C.gold }}>see <span className="hf-mono">examples/real_data_demo.py</span></span> &mdash; and on 29 April 2026
                a 1MW/2MWh asset would have made <span style={{ color: C.text }}>€323</span> in a single
                day under the same MILP. The framework is asset-generic: every parameter on the left is a
                slider, schedules respect power, energy, SoC, and cycle constraints simultaneously, and the
                Python side ships three forecasters (Perfect, Smart, Naive), a daily-rolling backtester, and
                HEnEx / ENTSO-E / Open-Meteo data adapters. Same{" "}
                <span style={{ color: C.gold }}>BatteryAsset</span> dataclass, any battery, any market
                window. Try sliding the duration from 1h to 4h and watch the cycle cap
                bind differently.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
